// mm/src/steps/downloadStep.js
import React, { useMemo } from 'react';
import { useWorkflow } from '../store/workflowContext';

const PACKAGES = [
  {
    key: 'basic',
    name: 'Basic Package',
    price: 49,
    subtitle: 'Essential files for self-publishing',
    bullets: ['Print PDF (PDF/X-1a compliant)', 'EPUB3 for digital distribution', 'Basic metadata JSON', 'Email delivery'],
    badge: null,
  },
  {
    key: 'standard',
    name: 'Standard Package',
    price: 99,
    subtitle: 'Complete publishing toolkit',
    bullets: [
      'Everything in Basic',
      'Multi-platform optimization',
      'Enhanced metadata with keywords',
      'Platform submission guidelines',
      'Priority email support',
    ],
    badge: 'Most Popular',
  },
  {
    key: 'premium',
    name: 'Premium Package',
    price: 199,
    subtitle: 'Professional publishing suite',
    bullets: [
      'Everything in Standard',
      'Professional cover suggestions',
      'Marketing copy templates',
      'ISBN registration assistance',
      'Distribution strategy guide',
      'White-glove setup support',
    ],
    badge: null,
  },
];

const Check = () => (
  <span className="inline-flex items-center justify-center w-5 h-5 rounded-full bg-emerald-50 text-emerald-600 border border-emerald-200">
    ✓
  </span>
);

const PackageCard = ({ pkg, selected, onSelect }) => {
  return (
    <button
      type="button"
      onClick={onSelect}
      className={[
        'relative text-left border rounded-xl p-6 bg-white transition w-full',
        selected ? 'border-blue-600 ring-1 ring-blue-600' : 'border-slate-200 hover:border-slate-300',
      ].join(' ')}
    >
      {pkg.badge ? (
        <div className="absolute -top-3 left-1/2 -translate-x-1/2 px-3 py-1 text-xs rounded-full bg-blue-600 text-white">
          {pkg.badge}
        </div>
      ) : null}

      <div className="text-lg font-semibold text-slate-900">{pkg.name}</div>
      <div className="mt-2 text-4xl font-bold text-blue-600">${pkg.price}</div>
      <div className="mt-2 text-sm text-slate-500">{pkg.subtitle}</div>

      <div className="mt-5 space-y-3">
        {pkg.bullets.map((b) => (
          <div key={b} className="flex items-start gap-3 text-sm text-slate-700">
            <Check />
            <div>{b}</div>
          </div>
        ))}
      </div>
    </button>
  );
};

const DownloadStep = () => {
  const { bookDetails, design, details, checkout, setCheckout } = useWorkflow();

  const selectedPkg = useMemo(
    () => PACKAGES.find((p) => p.key === checkout.selectedPackage) || PACKAGES[1],
    [checkout.selectedPackage]
  );

  const authorDisplay = useMemo(() => {
    // Prefer Details names if provided; fallback to metadata author
    const prefix = (details?.prefix || '').trim();
    const first = (details?.firstName || '').trim();
    const last = (details?.lastName || '').trim();
    const suffix = (details?.suffix || '').trim();

    const nameParts = [prefix, first, last, suffix].filter(Boolean);
    if (nameParts.length) return nameParts.join(' ');

    const metaAuthor = (bookDetails?.author || '').trim();
    return metaAuthor || 'Author Name';
  }, [details, bookDetails]);

  const formatDisplay = useMemo(() => {
    const trim = design?.trim || '—';
    const typo = design?.typography || '—';
    const layout = design?.layout || '—';
    return { trim, typo, layout };
  }, [design]);

  const email = checkout.deliveryEmail || '';

  const emailValid = useMemo(() => {
    const v = email.trim();
    if (!v) return false;
    // lightweight validation
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v);
  }, [email]);

  const handlePay = async () => {
    // For now, this is a placeholder hook.
    // In production you will:
    // 1) POST to your backend: /api/checkout/session
    // 2) Receive a Stripe Checkout Session URL
    // 3) window.location.href = sessionUrl
    if (!emailValid) return;

    setCheckout((prev) => ({ ...prev, status: 'creating_session' }));

    try {
      // TODO: replace with real API call
      // const { data } = await createCheckoutSession({ package: selectedPkg.key, email, ... });
      // window.location.href = data.url;

      // temporary demo behavior:
      setTimeout(() => {
        setCheckout((prev) => ({ ...prev, status: 'redirecting' }));
      }, 400);
    } catch (e) {
      console.error(e);
      setCheckout((prev) => ({ ...prev, status: 'failed' }));
    }
  };

  return (
    <div className="space-y-6">
      {/* Choose Your Package */}
      <div className="border rounded-xl p-6 bg-white">
        <h2 className="text-2xl font-semibold text-slate-900">Choose Your Package</h2>

        <div className="mt-6 grid grid-cols-1 md:grid-cols-3 gap-5">
          {PACKAGES.map((p) => (
            <PackageCard
              key={p.key}
              pkg={p}
              selected={checkout.selectedPackage === p.key}
              onSelect={() => setCheckout((prev) => ({ ...prev, selectedPackage: p.key }))}
            />
          ))}
        </div>
      </div>

      {/* Order Summary */}
      <div className="border rounded-xl p-6 bg-white">
        <h2 className="text-2xl font-semibold text-slate-900">Order Summary</h2>

        <div className="mt-6 space-y-3 text-sm">
          <div className="flex items-center justify-between">
            <div className="text-slate-600">Book Title:</div>
            <div className="text-slate-900 font-medium">{(bookDetails?.title || 'Your Book').trim() || 'Your Book'}</div>
          </div>

          <div className="flex items-center justify-between">
            <div className="text-slate-600">Author:</div>
            <div className="text-slate-900 font-medium">{authorDisplay}</div>
          </div>

          <div className="flex items-center justify-between">
            <div className="text-slate-600">Format:</div>
            <div className="text-slate-900 font-medium">
              {formatDisplay.trim} • {formatDisplay.typo} • {formatDisplay.layout}
            </div>
          </div>

          <div className="border-t mt-4 pt-4 flex items-center justify-between">
            <div className="text-slate-900 font-semibold">Total:</div>
            <div className="text-slate-900 font-semibold">${selectedPkg.price}</div>
          </div>
        </div>
      </div>

      {/* Payment & Delivery */}
      <div className="border rounded-xl p-6 bg-white">
        <h2 className="text-2xl font-semibold text-slate-900">Payment &amp; Delivery</h2>

        <div className="mt-6">
          <label className="block text-sm font-medium text-slate-700">
            Email Address for File Delivery <span className="text-red-500">*</span>
          </label>
          <input
            value={email}
            onChange={(e) => setCheckout((prev) => ({ ...prev, deliveryEmail: e.target.value }))}
            placeholder="your.email@example.com"
            className="mt-2 w-full border rounded-md px-3 py-2"
          />
          <div className="mt-2 text-xs text-slate-500">Your formatted files will be delivered to this email address</div>
        </div>

        <div className="mt-6 rounded-lg border bg-slate-50 p-4 text-sm text-slate-700">
          <span className="font-semibold">Secure Payment:</span> All transactions are processed securely through Stripe.
          Your payment information is encrypted and never stored on our servers.
        </div>

        <button
          type="button"
          onClick={handlePay}
          disabled={!emailValid || checkout.status === 'creating_session' || checkout.status === 'redirecting'}
          className={[
            'mt-6 w-full py-4 rounded-lg font-semibold text-white transition',
            !emailValid || checkout.status === 'creating_session' || checkout.status === 'redirecting'
              ? 'bg-blue-300 cursor-not-allowed'
              : 'bg-blue-600 hover:bg-blue-700',
          ].join(' ')}
        >
          {checkout.status === 'creating_session' ? 'Starting checkout…' : `Pay $${selectedPkg.price}`}
        </button>

        {checkout.status === 'failed' ? (
          <div className="mt-3 text-sm text-red-600">Payment setup failed. Please try again.</div>
        ) : null}
      </div>
    </div>
  );
};

export default DownloadStep;
